import React, { useState, useMemo, useEffect } from 'react';
import { 
  LayoutDashboard, 
  Wallet, 
  Package, 
  CheckSquare, 
  Users, 
  Bus, 
  FileText, 
  LogOut,
  Bell,
  Search,
  Plus,
  ArrowUpRight,
  TrendingUp,
  Activity,
  X,
  Save,
  Clock,
  MapPin,
  ShieldCheck
} from 'lucide-react';
import { AppTab, Expense, InventoryItem, Task, StaffRecord, BusSchedule, Policy } from './types';
import { MOCK_EXPENSES, MOCK_INVENTORY, MOCK_TASKS, MOCK_STAFF, MOCK_BUS, MOCK_POLICIES } from './constants';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';

// Helper for localStorage
const storage = {
  get: <T,>(key: string, defaultValue: T): T => {
    const saved = localStorage.getItem(`pb_portal_${key}`);
    return saved ? JSON.parse(saved) : defaultValue;
  },
  set: <T,>(key: string, value: T): void => {
    localStorage.setItem(`pb_portal_${key}`, JSON.stringify(value));
  }
};

// Components
const SidebarItem: React.FC<{ 
  icon: React.ElementType; 
  label: string; 
  active: boolean; 
  onClick: () => void 
}> = ({ icon: Icon, label, active, onClick }) => (
  <button
    onClick={onClick}
    className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-all duration-200 ${
      active 
        ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-200' 
        : 'text-slate-500 hover:bg-slate-100'
    }`}
  >
    <Icon size={20} />
    <span className="font-medium text-sm">{label}</span>
  </button>
);

const StatCard: React.FC<{ icon: React.ElementType; label: string; value: string; color: string }> = ({ icon: Icon, label, value, color }) => (
  <div className="bg-white p-6 rounded-xl border border-slate-100 shadow-sm flex items-center space-x-4">
    <div className={`p-3 rounded-lg ${color} bg-opacity-10 text-${color.split('-')[1]}-600`}>
      <Icon size={24} />
    </div>
    <div>
      <p className="text-slate-500 text-xs font-medium uppercase tracking-wider">{label}</p>
      <h3 className="text-2xl font-bold text-slate-800">{value}</h3>
    </div>
  </div>
);

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.DASHBOARD);

  // Persisted States
  const [expenses, setExpenses] = useState<Expense[]>(() => storage.get('expenses', MOCK_EXPENSES));
  const [inventory, setInventory] = useState<InventoryItem[]>(() => storage.get('inventory', MOCK_INVENTORY));
  const [tasks, setTasks] = useState<Task[]>(() => storage.get('tasks', MOCK_TASKS));
  const [staff, setStaff] = useState<StaffRecord[]>(() => storage.get('staff', MOCK_STAFF));
  const [busSchedules, setBusSchedules] = useState<BusSchedule[]>(() => storage.get('busSchedules', MOCK_BUS));

  // Sync with storage whenever state changes
  useEffect(() => storage.set('expenses', expenses), [expenses]);
  useEffect(() => storage.set('inventory', inventory), [inventory]);
  useEffect(() => storage.set('tasks', tasks), [tasks]);
  useEffect(() => storage.set('staff', staff), [staff]);
  useEffect(() => storage.set('busSchedules', busSchedules), [busSchedules]);

  // Modal State for Staff
  const [isStaffModalOpen, setIsStaffModalOpen] = useState(false);
  const [newStaff, setNewStaff] = useState<Omit<StaffRecord, 'id'>>({
    name: '',
    role: '',
    phone: '',
    email: '',
    joiningDate: new Date().toISOString().split('T')[0],
    agreementSigned: false,
    guarantor: {
      name: '',
      phone: '',
      address: ''
    }
  });

  // Modal State for Transportation
  const [isTransportModalOpen, setIsTransportModalOpen] = useState(false);
  const [newBusSchedule, setNewBusSchedule] = useState<Omit<BusSchedule, 'id'>>({
    busNumber: '',
    route: '',
    pickupTime: '',
    driver: {
      name: '',
      phone: '',
      homeAddress: '',
      agencyDetails: ''
    }
  });

  const totalExpenses = useMemo(() => expenses.reduce((acc, curr) => acc + curr.amount, 0), [expenses]);
  const pendingTasks = useMemo(() => tasks.filter(t => !t.completed).length, [tasks]);
  const itemsNeeded = useMemo(() => inventory.filter(i => i.needed).length, [inventory]);

  const handleStaffSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const id = Date.now().toString();
    setStaff([...staff, { ...newStaff, id }]);
    setIsStaffModalOpen(false);
    setNewStaff({
      name: '',
      role: '',
      phone: '',
      email: '',
      joiningDate: new Date().toISOString().split('T')[0],
      agreementSigned: false,
      guarantor: { name: '', phone: '', address: '' }
    });
  };

  const handleTransportSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const id = Date.now().toString();
    setBusSchedules([...busSchedules, { ...newBusSchedule, id }]);
    setIsTransportModalOpen(false);
    setNewBusSchedule({
      busNumber: '',
      route: '',
      pickupTime: '',
      driver: {
        name: '',
        phone: '',
        homeAddress: '',
        agencyDetails: ''
      }
    });
  };

  const renderDashboard = () => (
    <div className="space-y-6 animate-fadeIn">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <StatCard icon={TrendingUp} label="Total Expenses" value={`$${totalExpenses.toLocaleString()}`} color="bg-rose-500" />
        <StatCard icon={CheckSquare} label="Pending Tasks" value={pendingTasks.toString()} color="bg-amber-500" />
        <StatCard icon={Package} label="Items Needed" value={itemsNeeded.toString()} color="bg-indigo-500" />
        <StatCard icon={Activity} label="Active Staff" value={staff.length.toString()} color="bg-emerald-500" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 bg-white p-6 rounded-xl border border-slate-100 shadow-sm">
          <div className="flex justify-between items-center mb-6">
            <h2 className="text-lg font-bold text-slate-800">Expense Analytics</h2>
            <div className="flex items-center text-xs text-slate-400 font-medium">
              <Save size={14} className="mr-1" />
              Auto-saved locally
            </div>
          </div>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={expenses}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="category" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12}} />
                <Tooltip cursor={{fill: '#f8fafc'}} />
                <Bar dataKey="amount" radius={[4, 4, 0, 0]}>
                  {expenses.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={index % 2 === 0 ? '#4f46e5' : '#818cf8'} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-6 rounded-xl border border-slate-100 shadow-sm">
          <h2 className="text-lg font-bold text-slate-800 mb-4">Upcoming Tasks</h2>
          <div className="space-y-4">
            {tasks.filter(t => !t.completed).slice(0, 4).map(task => (
              <div key={task.id} className="flex items-start space-x-3 p-3 hover:bg-slate-50 rounded-lg transition-colors border border-transparent hover:border-slate-100">
                <input 
                  type="checkbox" 
                  checked={task.completed} 
                  className="mt-1 rounded border-slate-300 text-indigo-600 focus:ring-indigo-500"
                  onChange={() => {
                    setTasks(tasks.map(t => t.id === task.id ? {...t, completed: !t.completed} : t));
                  }}
                />
                <div className="flex-1">
                  <p className={`text-sm font-medium ${task.completed ? 'line-through text-slate-400' : 'text-slate-700'}`}>
                    {task.title}
                  </p>
                  <p className="text-xs text-slate-400 mt-0.5">{task.dueDate}</p>
                </div>
              </div>
            ))}
            {tasks.filter(t => !t.completed).length === 0 && (
              <p className="text-sm text-slate-400 text-center py-4 italic">No pending tasks</p>
            )}
            <button 
              onClick={() => setActiveTab(AppTab.TASKS)}
              className="w-full py-2 text-sm text-indigo-600 font-medium hover:bg-indigo-50 rounded transition-colors"
            >
              Manage Tasks
            </button>
          </div>
        </div>
      </div>
    </div>
  );

  const renderStaffModal = () => (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/40 backdrop-blur-sm p-4">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-2xl max-h-[90vh] overflow-y-auto">
        <div className="p-6 border-b border-slate-100 flex justify-between items-center sticky top-0 bg-white z-10">
          <div>
            <h2 className="text-xl font-bold text-slate-800">Add New Staff Record</h2>
            <p className="text-sm text-slate-500">Data will be persisted to local storage</p>
          </div>
          <button 
            onClick={() => setIsStaffModalOpen(false)}
            className="p-2 hover:bg-slate-100 rounded-full transition-colors"
          >
            <X size={20} className="text-slate-400" />
          </button>
        </div>
        <form onSubmit={handleStaffSubmit} className="p-8 space-y-8">
          <div className="space-y-4">
            <h3 className="text-xs font-black text-indigo-600 uppercase tracking-widest flex items-center">
              <span className="w-4 h-px bg-indigo-600 mr-2"></span>
              Basic Information
            </h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-1">
                <label className="text-xs font-bold text-slate-600 ml-1">Full Name</label>
                <input required type="text" value={newStaff.name} onChange={e => setNewStaff({...newStaff, name: e.target.value})} placeholder="e.g. Ama Serwaa" className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none transition-all focus:ring-2 focus:ring-indigo-100" />
              </div>
              <div className="space-y-1">
                <label className="text-xs font-bold text-slate-600 ml-1">Role / Position</label>
                <input required type="text" value={newStaff.role} onChange={e => setNewStaff({...newStaff, role: e.target.value})} placeholder="e.g. KG1 Teacher" className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none transition-all focus:ring-2 focus:ring-indigo-100" />
              </div>
              <div className="space-y-1">
                <label className="text-xs font-bold text-slate-600 ml-1">Email Address</label>
                <input required type="email" value={newStaff.email} onChange={e => setNewStaff({...newStaff, email: e.target.value})} placeholder="ama@princessbilingual.edu" className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none transition-all focus:ring-2 focus:ring-indigo-100" />
              </div>
              <div className="space-y-1">
                <label className="text-xs font-bold text-slate-600 ml-1">Phone Number</label>
                <input required type="tel" value={newStaff.phone} onChange={e => setNewStaff({...newStaff, phone: e.target.value})} placeholder="+233 ..." className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none transition-all focus:ring-2 focus:ring-indigo-100" />
              </div>
              <div className="space-y-1">
                <label className="text-xs font-bold text-slate-600 ml-1">Joining Date</label>
                <input required type="date" value={newStaff.joiningDate} onChange={e => setNewStaff({...newStaff, joiningDate: e.target.value})} className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none transition-all focus:ring-2 focus:ring-indigo-100" />
              </div>
              <div className="flex items-end pb-2">
                <label className="flex items-center space-x-3 cursor-pointer select-none group">
                  <div className="relative">
                    <input type="checkbox" checked={newStaff.agreementSigned} onChange={e => setNewStaff({...newStaff, agreementSigned: e.target.checked})} className="sr-only" />
                    <div className={`w-10 h-6 rounded-full transition-colors ${newStaff.agreementSigned ? 'bg-indigo-600' : 'bg-slate-200'}`}></div>
                    <div className={`absolute left-1 top-1 w-4 h-4 bg-white rounded-full transition-transform ${newStaff.agreementSigned ? 'translate-x-4' : ''}`}></div>
                  </div>
                  <span className="text-sm font-medium text-slate-700">Agreement Signed?</span>
                </label>
              </div>
            </div>
          </div>
          <div className="space-y-4">
            <h3 className="text-xs font-black text-rose-600 uppercase tracking-widest flex items-center">
              <span className="w-4 h-px bg-rose-600 mr-2"></span>
              Guarantor Information
            </h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-1">
                <label className="text-xs font-bold text-slate-600 ml-1">Guarantor Full Name</label>
                <input required type="text" value={newStaff.guarantor.name} onChange={e => setNewStaff({...newStaff, guarantor: {...newStaff.guarantor, name: e.target.value}})} placeholder="Guarantor Name" className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none transition-all focus:ring-2 focus:ring-indigo-100" />
              </div>
              <div className="space-y-1">
                <label className="text-xs font-bold text-slate-600 ml-1">Guarantor Phone</label>
                <input required type="tel" value={newStaff.guarantor.phone} onChange={e => setNewStaff({...newStaff, guarantor: {...newStaff.guarantor, phone: e.target.value}})} placeholder="Guarantor Phone" className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none transition-all focus:ring-2 focus:ring-indigo-100" />
              </div>
              <div className="md:col-span-2 space-y-1">
                <label className="text-xs font-bold text-slate-600 ml-1">Residential Address</label>
                <textarea required rows={2} value={newStaff.guarantor.address} onChange={e => setNewStaff({...newStaff, guarantor: {...newStaff.guarantor, address: e.target.value}})} placeholder="Full physical address of the guarantor..." className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none transition-all resize-none focus:ring-2 focus:ring-indigo-100" />
              </div>
            </div>
          </div>
          <div className="pt-4 flex space-x-3">
            <button type="button" onClick={() => setIsStaffModalOpen(false)} className="flex-1 py-3 text-sm font-bold text-slate-500 bg-slate-100 rounded-xl hover:bg-slate-200 transition-all">Cancel</button>
            <button type="submit" className="flex-[2] py-3 text-sm font-bold text-white bg-indigo-600 rounded-xl hover:bg-indigo-700 shadow-lg shadow-indigo-100 transition-all">Register Staff Member</button>
          </div>
        </form>
      </div>
    </div>
  );

  const renderTransportModal = () => (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/40 backdrop-blur-sm p-4">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-2xl max-h-[90vh] overflow-y-auto animate-modalIn">
        <div className="p-6 border-b border-slate-100 flex justify-between items-center sticky top-0 bg-white z-10">
          <div>
            <h2 className="text-xl font-bold text-slate-800">Add New Bus Route</h2>
            <p className="text-sm text-slate-500">Configure route and driver details</p>
          </div>
          <button 
            onClick={() => setIsTransportModalOpen(false)}
            className="p-2 hover:bg-slate-100 rounded-full transition-colors"
          >
            <X size={20} className="text-slate-400" />
          </button>
        </div>
        <form onSubmit={handleTransportSubmit} className="p-8 space-y-8">
          {/* Route Info */}
          <div className="space-y-4">
            <h3 className="text-xs font-black text-amber-600 uppercase tracking-widest flex items-center">
              <span className="w-4 h-px bg-amber-600 mr-2"></span>
              Route Configuration
            </h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-1">
                <label className="text-xs font-bold text-slate-600 ml-1">Bus Number / ID</label>
                <input required type="text" value={newBusSchedule.busNumber} onChange={e => setNewBusSchedule({...newBusSchedule, busNumber: e.target.value})} placeholder="e.g. PB-05" className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none transition-all focus:ring-2 focus:ring-amber-100" />
              </div>
              <div className="space-y-1">
                <label className="text-xs font-bold text-slate-600 ml-1">Pickup Time</label>
                <input required type="text" value={newBusSchedule.pickupTime} onChange={e => setNewBusSchedule({...newBusSchedule, pickupTime: e.target.value})} placeholder="e.g. 07:00 AM" className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none transition-all focus:ring-2 focus:ring-amber-100" />
              </div>
              <div className="md:col-span-2 space-y-1">
                <label className="text-xs font-bold text-slate-600 ml-1">Route Description</label>
                <input required type="text" value={newBusSchedule.route} onChange={e => setNewBusSchedule({...newBusSchedule, route: e.target.value})} placeholder="e.g. Route Gamma: East Legon - Madina" className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none transition-all focus:ring-2 focus:ring-amber-100" />
              </div>
            </div>
          </div>

          {/* Driver Info */}
          <div className="space-y-4">
            <h3 className="text-xs font-black text-indigo-600 uppercase tracking-widest flex items-center">
              <span className="w-4 h-px bg-indigo-600 mr-2"></span>
              Driver Information
            </h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-1">
                <label className="text-xs font-bold text-slate-600 ml-1">Driver's Full Name</label>
                <input required type="text" value={newBusSchedule.driver.name} onChange={e => setNewBusSchedule({...newBusSchedule, driver: {...newBusSchedule.driver, name: e.target.value}})} placeholder="Driver Name" className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none transition-all focus:ring-2 focus:ring-indigo-100" />
              </div>
