          <div key={bus.id} className="bg-white rounded-2xl border border-slate-100 shadow-sm p-6 relative group hover:shadow-xl transition-all duration-300">
            <button onClick={() => { if(confirm('Delete route?')) setBusSchedules(busSchedules.filter(b => b.id !== bus.id)) }} className="absolute top-4 right-4 text-slate-200 hover:text-rose-500 opacity-0 group-hover:opacity-100 transition-all"><X size={18} /></button>
            <div className="flex justify-between items-start mb-6">
              <div className="flex items-center space-x-4"><div className="p-3 bg-amber-50 text-amber-600 rounded-2xl"><Bus size={28} /></div>
                <div><h3 className="font-black text-slate-800 text-lg">Bus {bus.busNumber}</h3><div className="flex items-center text-xs text-slate-400 mt-0.5 font-bold tracking-wider"><MapPin size={12} className="mr-1" />{bus.route}</div></div>
              </div>
              <div className="text-right"><p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Morning Pickup</p><div className="flex items-center justify-end text-lg font-black text-indigo-600"><Clock size={18} className="mr-2 text-indigo-300" />{bus.pickupTime}</div></div>
            </div>
            <div className="grid grid-cols-2 gap-4"><div className="p-4 bg-slate-50/50 rounded-2xl border border-slate-100/50"><p className="text-[10px] font-black text-slate-400 uppercase tracking-tight mb-2">Driver Profile</p><p className="text-sm font-bold text-slate-800">{bus.driver.name}</p><p className="text-xs text-slate-500 mt-1 font-medium">{bus.driver.phone}</p></div>
              <div className="p-4 bg-slate-50/50 rounded-2xl border border-slate-100/50"><p className="text-[10px] font-black text-slate-400 uppercase tracking-tight mb-2">Home Address</p><p className="text-xs text-slate-700 italic">{bus.driver.homeAddress}</p></div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );

  const renderInventory = () => (
    <div className="bg-white rounded-xl border border-slate-100 shadow-sm overflow-hidden">
      <div className="p-6 border-b border-slate-50 flex justify-between items-center">
        <h2 className="text-lg font-bold text-slate-800">Inventory</h2>
        <button className="bg-indigo-600 text-white px-4 py-2 rounded-lg text-sm font-medium hover:bg-indigo-700">Add Item</button>
      </div>
      <div className="overflow-x-auto"><table className="w-full text-left">
        <thead><tr className="bg-slate-50 text-slate-500 text-xs font-bold uppercase tracking-wider"><th className="px-6 py-4">Item</th><th className="px-6 py-4">Stock</th><th className="px-6 py-4">Status</th><th className="px-6 py-4">Urgent</th><th className="px-6 py-4"></th></tr></thead>
        <tbody className="divide-y divide-slate-50">{inventory.map(i => (
          <tr key={i.id} className="hover:bg-slate-50 group">
            <td className="px-6 py-4 text-sm font-medium text-slate-800">{i.name}</td>
            <td className="px-6 py-4 text-sm text-slate-600">{i.quantity}</td>
            <td className="px-6 py-4"><span className={`px-2 py-1 rounded-full text-[10px] font-bold uppercase ${i.status === 'In Stock' ? 'bg-emerald-100 text-emerald-600' : 'bg-rose-100 text-rose-600'}`}>{i.status}</span></td>
            <td className="px-6 py-4">{i.needed ? <span className="flex items-center text-xs font-bold text-rose-500"><ArrowUpRight size={14} className="mr-1" /> Reorder</span> : '-'}</td>
            <td className="px-6 py-4"><button onClick={() => setInventory(inventory.filter(it => it.id !== i.id))} className="text-slate-200 hover:text-rose-500 opacity-0 group-hover:opacity-100 transition-all"><X size={16} /></button></td>
          </tr>
        ))}</tbody>
      </table></div>
    </div>
  );

  return (
    <div className="flex min-h-screen bg-slate-50 overflow-x-hidden">
      {/* Modals & Panels */}
      {isStaffModalOpen && renderStaffModal()}
      {isTransportModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/40 backdrop-blur-sm p-4">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-2xl max-h-[90vh] overflow-y-auto p-8">
            <div className="flex justify-between mb-6"><h2 className="text-xl font-bold">New Route</h2><button onClick={() => setIsTransportModalOpen(false)}><X size={20} /></button></div>
            <form onSubmit={handleTransportSubmit} className="space-y-4">
              <input required type="text" placeholder="Bus Number" value={newBusSchedule.busNumber} onChange={e => setNewBusSchedule({...newBusSchedule, busNumber: e.target.value})} className="w-full px-4 py-2 border rounded-xl" />
              <input required type="text" placeholder="Route" value={newBusSchedule.route} onChange={e => setNewBusSchedule({...newBusSchedule, route: e.target.value})} className="w-full px-4 py-2 border rounded-xl" />
              <input required type="text" placeholder="Pickup Time" value={newBusSchedule.pickupTime} onChange={e => setNewBusSchedule({...newBusSchedule, pickupTime: e.target.value})} className="w-full px-4 py-2 border rounded-xl" />
              <button type="submit" className="w-full py-3 bg-amber-500 text-white rounded-xl font-bold">Add Route</button>
            </form>
          </div>
        </div>
      )}
      {isTaskModalOpen && renderTaskModal()}
      {renderAiGuidancePanel()}
      {isAiPanelOpen && <div className="fixed inset-0 bg-slate-900/20 z-[55] backdrop-blur-xs" onClick={() => setIsAiPanelOpen(false)} />}

      {/* Sidebar */}
      <aside className="w-64 bg-white border-r border-slate-100 p-6 flex flex-col fixed h-full z-10">
        <div className="mb-10 px-4"><h1 className="text-xl font-black text-indigo-600">Princess Bilingual</h1><p className="text-[10px] text-slate-400 font-bold tracking-[0.2em] uppercase mt-1">Management Portal</p></div>
        <nav className="flex-1 space-y-1">
          <SidebarItem icon={LayoutDashboard} label="Dashboard" active={activeTab === AppTab.DASHBOARD} onClick={() => setActiveTab(AppTab.DASHBOARD)} />
          <SidebarItem icon={Wallet} label="Expenses" active={activeTab === AppTab.EXPENSES} onClick={() => setActiveTab(AppTab.EXPENSES)} />
          <SidebarItem icon={Package} label="Inventory" active={activeTab === AppTab.INVENTORY} onClick={() => setActiveTab(AppTab.INVENTORY)} />
          <SidebarItem icon={CheckSquare} label="Tasks" active={activeTab === AppTab.TASKS} onClick={() => setActiveTab(AppTab.TASKS)} />
          <SidebarItem icon={Users} label="Staff Records" active={activeTab === AppTab.STAFF} onClick={() => setActiveTab(AppTab.STAFF)} />
          <SidebarItem icon={Bus} label="Transportation" active={activeTab === AppTab.TRANSPORT} onClick={() => setActiveTab(AppTab.TRANSPORT)} />
          <SidebarItem icon={FileText} label="Policy Center" active={activeTab === AppTab.POLICIES} onClick={() => setActiveTab(AppTab.POLICIES)} />
        </nav>
        <div className="mt-auto border-t border-slate-50 pt-6">
          <div className="bg-slate-50 rounded-xl p-4 mb-4 flex items-center space-x-3">
            <div className="w-10 h-10 rounded-full bg-indigo-500 flex items-center justify-center text-white font-bold shadow-lg shadow-indigo-200">G</div>
            <div><p className="text-sm font-black text-slate-800">Madam Gloria</p><p className="text-[10px] text-slate-400 font-bold uppercase tracking-tighter">Proprietress</p></div>
          </div>
          <button className="flex items-center space-x-2 text-slate-400 hover:text-rose-500 w-full px-4 transition-all text-sm font-bold"><LogOut size={18} /><span>Sign Out</span></button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 ml-64 p-8">
        <header className="flex justify-between items-center mb-10">
          <div><h1 className="text-2xl font-black text-slate-800 capitalize tracking-tight">{activeTab.replace('-', ' ')}</h1><p className="text-slate-400 text-sm mt-1 font-medium italic">Empowering the future, one student at a time.</p></div>
          <div className="flex items-center space-x-4">
            <div className="relative"><Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} /><input type="text" placeholder="Search portal..." className="pl-10 pr-4 py-2.5 bg-white border border-slate-100 rounded-xl text-sm outline-none focus:ring-4 focus:ring-indigo-50 transition-all w-64 shadow-sm" /></div>
            <button className="p-2.5 bg-white border border-slate-100 rounded-xl text-slate-500 hover:text-indigo-600 relative shadow-sm"><Bell size={20} /><span className="absolute top-2 right-2.5 w-2 h-2 bg-rose-500 rounded-full border-2 border-white"></span></button>
          </div>
        </header>

        {activeTab === AppTab.DASHBOARD && renderDashboard()}
        {activeTab === AppTab.EXPENSES && renderExpenses()}
        {activeTab === AppTab.STAFF && renderStaff()}
        {activeTab === AppTab.TRANSPORT && renderTransport()}
        {activeTab === AppTab.INVENTORY && renderInventory()}
        {activeTab === AppTab.POLICIES && (
           <div className="max-w-4xl mx-auto bg-white p-8 rounded-2xl border border-slate-100 shadow-sm">
             <h2 className="text-3xl font-black text-slate-800 mb-8">Policy Center</h2>
             <div className="space-y-8">{MOCK_POLICIES.map(p => (
               <div key={p.id} className="relative pl-8 border-l-2 border-indigo-500">
                 <h3 className="text-xl font-bold">{p.title}</h3>
                 <p className="mt-2 text-slate-600 bg-slate-50 p-6 rounded-xl text-sm leading-relaxed">{p.content}</p>
               </div>
             ))}</div>
           </div>
        )}
        {activeTab === AppTab.TASKS && renderTasks()}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { 
  LayoutDashboard, 
  Wallet, 
  Package, 
  CheckSquare, 
  Users, 
  Bus, 
  FileText, 
  LogOut,
  Bell,
  Search,
  Plus,
  ArrowUpRight,
  TrendingUp,
  Activity,
  X,
  Save,
  Clock,
  MapPin,
  ShieldCheck,
  Sparkles,
  Loader2,
  ChevronRight,
  AlertTriangle,
  Filter,
  BrainCircuit
} from 'lucide-react';
import { GoogleGenAI } from "@google/genai";
import { AppTab, Expense, InventoryItem, Task, StaffRecord, BusSchedule, Policy } from './types';
import { MOCK_EXPENSES, MOCK_INVENTORY, MOCK_TASKS, MOCK_STAFF, MOCK_BUS, MOCK_POLICIES } from './constants';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';

// Helper for localStorage
const storage = {
  get: <T,>(key: string, defaultValue: T): T => {
    const saved = localStorage.getItem(`pb_portal_${key}`);
    return saved ? JSON.parse(saved) : defaultValue;
  },
  set: <T,>(key: string, value: T): void => {
    localStorage.setItem(`pb_portal_${key}`, JSON.stringify(value));
  }
};

// Components
const SidebarItem: React.FC<{ 
  icon: React.ElementType; 
  label: string; 
  active: boolean; 
  onClick: () => void 
}> = ({ icon: Icon, label, active, onClick }) => (
  <button
    onClick={onClick}
    className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-all duration-200 ${
      active 
        ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-200' 
        : 'text-slate-500 hover:bg-slate-100'
    }`}
  >
    <Icon size={20} />
    <span className="font-medium text-sm">{label}</span>
  </button>
);

const StatCard: React.FC<{ icon: React.ElementType; label: string; value: string; color: string }> = ({ icon: Icon, label, value, color }) => (
  <div className="bg-white p-6 rounded-xl border border-slate-100 shadow-sm flex items-center space-x-4">
    <div className={`p-3 rounded-lg ${color} bg-opacity-10 text-${color.split('-')[1]}-600`}>
      <Icon size={24} />
    </div>
    <div>
      <p className="text-slate-500 text-xs font-medium uppercase tracking-wider">{label}</p>
      <h3 className="text-2xl font-bold text-slate-800">{value}</h3>
    </div>
  </div>
);

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.DASHBOARD);

  // Persisted States
  const [expenses, setExpenses] = useState<Expense[]>(() => storage.get('expenses', MOCK_EXPENSES));
  const [inventory, setInventory] = useState<InventoryItem[]>(() => storage.get('inventory', MOCK_INVENTORY));
  const [tasks, setTasks] = useState<Task[]>(() => storage.get('tasks', MOCK_TASKS));
  const [staff, setStaff] = useState<StaffRecord[]>(() => storage.get('staff', MOCK_STAFF));
  const [busSchedules, setBusSchedules] = useState<BusSchedule[]>(() => storage.get('busSchedules', MOCK_BUS));

  // Sync with storage
  useEffect(() => storage.set('expenses', expenses), [expenses]);
  useEffect(() => storage.set('inventory', inventory), [inventory]);
  useEffect(() => storage.set('tasks', tasks), [tasks]);
  useEffect(() => storage.set('staff', staff), [staff]);
  useEffect(() => storage.set('busSchedules', busSchedules), [busSchedules]);

  // Modals States
  const [isStaffModalOpen, setIsStaffModalOpen] = useState(false);
  const [isTransportModalOpen, setIsTransportModalOpen] = useState(false);
  const [isTaskModalOpen, setIsTaskModalOpen] = useState(false);
  const [isInventoryModalOpen, setIsInventoryModalOpen] = useState(false);
  const [isAiPanelOpen, setIsAiPanelOpen] = useState(false);
  const [aiGuidance, setAiGuidance] = useState<{title: string, content: string} | null>(null);
  const [isAiLoading, setIsAiLoading] = useState(false);

  // Form States
  const [newTask, setNewTask] = useState<Omit<Task, 'id' | 'completed'>>({
    title: '',
    dueDate: new Date().toISOString().split('T')[0],
    priority: 'Medium'
  });

  const [newInventoryItem, setNewInventoryItem] = useState<Omit<InventoryItem, 'id'>>({
    name: '',
    category: 'Stationery',
    quantity: 0,
    status: 'In Stock',
    needed: false
  });

  const [newStaff, setNewStaff] = useState<Omit<StaffRecord, 'id'>>({
    name: '', role: '', phone: '', email: '',
    joiningDate: new Date().toISOString().split('T')[0],
    agreementSigned: false,
    guarantor: { name: '', phone: '', address: '' }
  });

  const [newBusSchedule, setNewBusSchedule] = useState<Omit<BusSchedule, 'id'>>({
    busNumber: '', route: '', pickupTime: '',
    driver: { name: '', phone: '', homeAddress: '', agencyDetails: '' }
  });

  const totalExpenses = useMemo(() => expenses.reduce((acc, curr) => acc + curr.amount, 0), [expenses]);
  const pendingTasks = useMemo(() => tasks.filter(t => !t.completed).length, [tasks]);
  const itemsNeeded = useMemo(() => inventory.filter(i => i.needed || i.status === 'Low' || i.status === 'Out of Stock').length, [inventory]);

  const handleTaskSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const id = Date.now().toString();
    setTasks([...tasks, { ...newTask, id, completed: false }]);
    setIsTaskModalOpen(false);
    setNewTask({ title: '', dueDate: new Date().toISOString().split('T')[0], priority: 'Medium' });
  };

  const handleInventorySubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const id = Date.now().toString();
    const status = newInventoryItem.quantity === 0 ? 'Out of Stock' : newInventoryItem.quantity < 10 ? 'Low' : 'In Stock';
    const needed = status !== 'In Stock';
    setInventory([...inventory, { ...newInventoryItem, id, status, needed }]);
    setIsInventoryModalOpen(false);
    setNewInventoryItem({ name: '', category: 'Stationery', quantity: 0, status: 'In Stock', needed: false });
  };

  const getAiGuidance = async (context: 'task' | 'inventory', data: any) => {
    setIsAiLoading(true);
    setIsAiPanelOpen(true);
    const title = context === 'task' ? data.title : "Inventory Insight";
    setAiGuidance({ title, content: '' });

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      let prompt = "";

      if (context === 'task') {
        prompt = `You are an expert school administrative assistant for Princess Bilingual School. 
        Madam Gloria, the proprietress, needs help with the following task: "${data.title}". 
        Provide a concise, professional, step-by-step action plan to accomplish this task efficiently.`;
      } else {
        const inventoryString = inventory.map(i => `${i.name} (${i.status}, Qty: ${i.quantity})`).join(', ');
        prompt = `You are an inventory optimization expert for Princess Bilingual School. 
        Here is the current inventory: ${inventoryString}.
        Based on this data, provide a "Smart restock priority list". 
        Suggest which items should be ordered immediately, which can wait, and offer 3 tips for cost-effective supply fetching in Ghana for a bilingual school.`;
      }

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });

      setAiGuidance({ title, content: response.text || "Sorry, I couldn't generate insights right now." });
    } catch (error) {
      setAiGuidance({ title, content: "Error connecting to AI assistant. Please check your connection." });
    } finally {
      setIsAiLoading(false);
    }
  };

  const handleStaffSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const id = Date.now().toString();
    setStaff([...staff, { ...newStaff, id }]);
    setIsStaffModalOpen(false);
  };

  const handleTransportSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const id = Date.now().toString();
    setBusSchedules([...busSchedules, { ...newBusSchedule, id }]);
    setIsTransportModalOpen(false);
  };

  const renderDashboard = () => (
    <div className="space-y-6 animate-fadeIn">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <StatCard icon={TrendingUp} label="Total Expenses" value={`$${totalExpenses.toLocaleString()}`} color="bg-rose-500" />
        <StatCard icon={CheckSquare} label="Pending Tasks" value={pendingTasks.toString()} color="bg-amber-500" />
        <StatCard icon={Package} label="Items Needed" value={itemsNeeded.toString()} color="bg-indigo-500" />
        <StatCard icon={Activity} label="Active Staff" value={staff.length.toString()} color="bg-emerald-500" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 bg-white p-6 rounded-xl border border-slate-100 shadow-sm">
          <div className="flex justify-between items-center mb-6">
            <h2 className="text-lg font-bold text-slate-800">Expense Analytics</h2>
            <div className="flex items-center text-xs text-slate-400 font-medium"><Save size={14} className="mr-1" />Auto-saved</div>
          </div>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={expenses}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="category" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12}} />
                <Tooltip cursor={{fill: '#f8fafc'}} />
                <Bar dataKey="amount" radius={[4, 4, 0, 0]}>
                  {expenses.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={index % 2 === 0 ? '#4f46e5' : '#818cf8'} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-6 rounded-xl border border-slate-100 shadow-sm">
          <h2 className="text-lg font-bold text-slate-800 mb-4">Pending Tasks</h2>
          <div className="space-y-4">
            {tasks.filter(t => !t.completed).slice(0, 4).map(task => (
              <div key={task.id} className="flex items-start space-x-3 p-3 hover:bg-slate-50 rounded-lg transition-colors border border-transparent hover:border-slate-100 group">
                <input 
                  type="checkbox" 
                  checked={task.completed} 
                  className="mt-1 rounded border-slate-300 text-indigo-600"
                  onChange={() => setTasks(tasks.map(t => t.id === task.id ? {...t, completed: !t.completed} : t))}
                />
                <div className="flex-1">
                  <p className="text-sm font-medium text-slate-700 truncate">{task.title}</p>
                  <p className="text-xs text-slate-400 mt-0.5">{task.dueDate}</p>
                </div>
                <button 
                  onClick={() => getAiGuidance('task', task)}
                  className="opacity-0 group-hover:opacity-100 text-indigo-500 transition-all p-1 hover:bg-indigo-50 rounded"
                >
                  <Sparkles size={14} />
                </button>
              </div>
            ))}
            <button onClick={() => setActiveTab(AppTab.TASKS)} className="w-full py-2 text-sm text-indigo-600 font-medium hover:bg-indigo-50 rounded transition-colors">Manage All Tasks</button>
          </div>
        </div>
      </div>
    </div>
  );

  const renderInventoryModal = () => (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/40 backdrop-blur-sm p-4">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md animate-modalIn">
        <div className="p-6 border-b border-slate-100 flex justify-between items-center">
          <h2 className="text-xl font-bold text-slate-800">Add Inventory Item</h2>
          <button onClick={() => setIsInventoryModalOpen(false)} className="p-2 hover:bg-slate-100 rounded-full"><X size={20} className="text-slate-400" /></button>
        </div>
        <form onSubmit={handleInventorySubmit} className="p-6 space-y-4">
          <div className="space-y-1">
            <label className="text-xs font-bold text-slate-600">Item Name</label>
            <input required type="text" value={newInventoryItem.name} onChange={e => setNewInventoryItem({...newInventoryItem, name: e.target.value})} placeholder="e.g. French Textbooks" className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none focus:ring-2 focus:ring-indigo-100" />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1">
              <label className="text-xs font-bold text-slate-600">Category</label>
              <select value={newInventoryItem.category} onChange={e => setNewInventoryItem({...newInventoryItem, category: e.target.value})} className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none">
                <option value="Stationery">Stationery</option>
                <option value="Cleaning">Cleaning</option>
                <option value="Office">Office</option>
                <option value="Books">Books</option>
                <option value="Furniture">Furniture</option>
              </select>
            </div>
            <div className="space-y-1">
              <label className="text-xs font-bold text-slate-600">Initial Quantity</label>
              <input required type="number" value={newInventoryItem.quantity} onChange={e => setNewInventoryItem({...newInventoryItem, quantity: parseInt(e.target.value)})} className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none" />
            </div>
          </div>
          <button type="submit" className="w-full py-3 text-sm font-bold text-white bg-indigo-600 rounded-xl hover:bg-indigo-700 shadow-lg shadow-indigo-100 transition-all">Add to Stock</button>
        </form>
      </div>
    </div>
  );

  const renderAiGuidancePanel = () => (
    <div className={`fixed inset-y-0 right-0 z-[60] w-96 bg-white shadow-2xl transform transition-transform duration-300 ease-in-out border-l border-slate-100 ${isAiPanelOpen ? 'translate-x-0' : 'translate-x-full'}`}>
      <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-indigo-600 text-white">
        <div className="flex items-center space-x-2">
          <Sparkles size={20} />
          <h2 className="font-bold">Princess AI Assistant</h2>
        </div>
        <button onClick={() => setIsAiPanelOpen(false)} className="p-1 hover:bg-white/20 rounded-full transition-colors"><X size={20} /></button>
      </div>
