                    <td className="px-6 py-4">
                      {item.needed ? (
                        <div className="flex items-center text-[10px] font-bold text-rose-500 uppercase tracking-tight">
                          <AlertTriangle size={12} className="mr-1" />
                          Needs Restock
                        </div>
                      ) : (
                        <span className="text-slate-300 text-[10px] font-bold">OPTIMAL</span>
                      )}
                    </td>
                    <td className="px-6 py-4 text-right">
                      <div className="flex justify-end space-x-2 opacity-0 group-hover:opacity-100 transition-all">
                        <button 
                          onClick={() => {
                            const newQty = prompt("Update quantity for " + item.name, item.quantity.toString());
                            if (newQty !== null) {
                              const qty = parseInt(newQty);
                              const status = qty === 0 ? 'Out of Stock' : qty < 10 ? 'Low' : 'In Stock';
                              const needed = status !== 'In Stock';
                              setInventory(inventory.map(i => i.id === item.id ? {...i, quantity: qty, status, needed} : i));
                            }
                          }}
                          className="p-1.5 text-indigo-400 hover:bg-indigo-50 rounded-lg transition-all"
                        >
                          <Save size={16} />
                        </button>
                        <button 
                          onClick={() => setInventory(inventory.filter(i => i.id !== item.id))}
                          className="p-1.5 text-rose-300 hover:text-rose-500 hover:bg-rose-50 rounded-lg transition-all"
                        >
                          <X size={16} />
                        </button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
            {inventory.length === 0 && (
              <div className="text-center py-20 bg-white">
                 <Package size={48} className="mx-auto text-slate-100 mb-4" />
                 <p className="text-slate-400 font-bold italic">Your inventory is empty. Madam Gloria, click 'Add Item' to track supplies.</p>
              </div>
            )}
          </div>
        </div>
      </div>
    );
  };

  const renderStaff = () => (
    <div className="space-y-6">
      <div className="flex justify-between items-center mb-6">
        <div>
          <h2 className="text-2xl font-black text-slate-800 tracking-tight">Staff Directory</h2>
          <p className="text-xs text-slate-400 font-medium mt-1">Total Employees: {staff.length}</p>
        </div>
        <button onClick={() => setIsStaffModalOpen(true)} className="bg-indigo-600 text-white px-5 py-2.5 rounded-xl text-sm font-bold flex items-center shadow-lg hover:bg-indigo-700 transition-all"><Plus size={18} className="mr-2" /> Add Staff Record</button>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {staff.map(record => (
          <div key={record.id} className="bg-white rounded-2xl border border-slate-100 shadow-sm p-6 hover:shadow-xl transition-all group">
            <div className="flex items-center space-x-4 mb-6">
              <div className="w-14 h-14 bg-gradient-to-br from-indigo-500 to-purple-600 text-white rounded-2xl flex items-center justify-center font-bold text-2xl">{record.name.charAt(0)}</div>
              <div>
                <h3 className="font-bold text-slate-800 text-lg leading-tight">{record.name}</h3>
                <p className="text-xs text-indigo-600 font-bold tracking-wide mt-0.5">{record.role}</p>
              </div>
            </div>
            <div className="space-y-2 mb-4">
              <p className="text-sm text-slate-500 flex items-center"><Users size={14} className="mr-2 text-indigo-300" />{record.email}</p>
              <p className="text-sm text-slate-500 flex items-center"><Activity size={14} className="mr-2 text-indigo-300" />Joined: {record.joiningDate}</p>
            </div>
            <div className="bg-slate-50 p-4 rounded-xl text-xs space-y-1">
               <p className="font-black text-slate-400 uppercase tracking-widest text-[9px]">Guarantor</p>
               <p className="font-bold text-slate-700">{record.guarantor?.name || 'N/A'}</p>
               <p className="text-slate-500">{record.guarantor?.phone || ''}</p>
            </div>
            <div className="mt-4 flex justify-between items-center">
              <span className={`text-[10px] font-black px-2 py-1 rounded-full ${record.agreementSigned ? 'bg-emerald-50 text-emerald-600' : 'bg-rose-50 text-rose-600'}`}>
