      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
        <div className="lg:col-span-3 space-y-4">
          {tasks.map(task => (
            <div key={task.id} className="bg-white p-5 rounded-2xl border border-slate-100 shadow-sm flex items-center hover:shadow-md transition-all group">
