                type="checkbox" 
                checked={task.completed} 
                className="w-5 h-5 rounded border-slate-300 text-indigo-600 focus:ring-indigo-500 cursor-pointer"
                onChange={() => setTasks(tasks.map(t => t.id === task.id ? {...t, completed: !t.completed} : t))}
              />
              <div className="ml-5 flex-1">
                <div className="flex items-center space-x-3">
                  <h4 className={`text-base font-bold transition-all ${task.completed ? 'text-slate-400 line-through' : 'text-slate-800'}`}>{task.title}</h4>
                  <span className={`px-2 py-0.5 rounded text-[10px] font-black uppercase tracking-wider ${
                    task.priority === 'High' ? 'bg-rose-50 text-rose-600' : 
                    task.priority === 'Medium' ? 'bg-amber-50 text-amber-600' : 'bg-slate-50 text-slate-600'
                  }`}>
                    {task.priority}
                  </span>
                </div>
                <div className="flex items-center mt-1 space-x-4">
                  <p className="text-xs text-slate-400 font-medium flex items-center"><Clock size={12} className="mr-1.5" /> Due: {task.dueDate}</p>
                </div>
              </div>
              <div className="flex items-center space-x-3">
                <button 
                  onClick={() => getAiGuidance('task', task)}
