                >
                  <Sparkles size={14} />
                  <span>AI Guide</span>
                </button>
                <button 
                  onClick={() => setTasks(tasks.filter(t => t.id !== task.id))}
                  className="p-1.5 text-slate-200 hover:text-rose-500 transition-colors"
                >
                  <X size={18} />
                </button>
              </div>
            </div>
          ))}
          {tasks.length === 0 && (
            <div className="text-center py-20 bg-white rounded-3xl border border-dashed border-slate-200">
               <CheckSquare size={48} className="mx-auto text-slate-100 mb-4" />
               <p className="text-slate-400 font-bold italic">No active tasks. Start by adding one above.</p>
            </div>
          )}
        </div>

        <div className="space-y-6">
           <div className="bg-indigo-600 rounded-3xl p-6 text-white shadow-xl shadow-indigo-100 relative overflow-hidden">
              <Sparkles className="absolute -right-4 -top-4 w-24 h-24 text-white/10 rotate-12" />
