          const amt = prompt("Amount ($):");
          const cat = prompt("Category:");
          if (desc && amt && cat) setExpenses([...expenses, { id: Date.now().toString(), date: new Date().toISOString().split('T')[0], description: desc, amount: parseFloat(amt), category: cat }]);
