        <thead><tr className="bg-slate-50 text-slate-500 text-xs font-bold uppercase tracking-wider"><th className="px-6 py-4">Date</th><th className="px-6 py-4">Category</th><th className="px-6 py-4">Description</th><th className="px-6 py-4">Amount</th><th className="px-6 py-4"></th></tr></thead>
