            <td className="px-6 py-4 text-sm font-bold text-slate-800">${e.amount}</td>
            <td className="px-6 py-4"><button onClick={() => setExpenses(expenses.filter(ex => ex.id !== e.id))} className="text-slate-300 hover:text-rose-500 opacity-0 group-hover:opacity-100 transition-all"><X size={16} /></button></td>
          </tr>
