      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {busSchedules.map(bus => (
          <div key={bus.id} className="bg-white rounded-2xl border border-slate-100 shadow-sm p-6 relative group hover:shadow-xl transition-all duration-300">
            <button onClick={() => { if(confirm('Delete route?')) setBusSchedules(busSchedules.filter(b => b.id !== bus.id)) }} className="absolute top-4 right-4 text-slate-200 hover:text-rose-500 opacity-0 group-hover:opacity-100 transition-all"><X size={18} /></button>
            <div className="flex justify-between items-start mb-6">
              <div className="flex items-center space-x-4"><div className="p-3 bg-amber-50 text-amber-600 rounded-2xl"><Bus size={28} /></div>
                <div><h3 className="font-black text-slate-800 text-lg">Bus {bus.busNumber}</h3><div className="flex items-center text-xs text-slate-400 mt-0.5 font-bold tracking-wider"><MapPin size={12} className="mr-1" />{bus.route}</div></div>
              </div>
              <div className="text-right"><p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Morning Pickup</p><div className="flex items-center justify-end text-lg font-black text-indigo-600"><Clock size={18} className="mr-2 text-indigo-300" />{bus.pickupTime}</div></div>
            </div>
            <div className="grid grid-cols-2 gap-4"><div className="p-4 bg-slate-50/50 rounded-2xl border border-slate-100/50"><p className="text-[10px] font-black text-slate-400 uppercase tracking-tight mb-2">Driver Profile</p><p className="text-sm font-bold text-slate-800">{bus.driver.name}</p><p className="text-xs text-slate-500 mt-1 font-medium">{bus.driver.phone}</p></div>
              <div className="p-4 bg-slate-50/50 rounded-2xl border border-slate-100/50"><p className="text-[10px] font-black text-slate-400 uppercase tracking-tight mb-2">Home Address</p><p className="text-xs text-slate-700 italic">{bus.driver.homeAddress}</p></div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );

  return (
    <div className="flex min-h-screen bg-slate-50 overflow-x-hidden">
      {/* Modals & Panels */}
      {isStaffModalOpen && renderStaffModal()}
      {isTransportModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/40 backdrop-blur-sm p-4">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-2xl max-h-[90vh] overflow-y-auto p-8">
            <div className="flex justify-between mb-6"><h2 className="text-xl font-bold">New Route</h2><button onClick={() => setIsTransportModalOpen(false)}><X size={20} /></button></div>
            <form onSubmit={handleTransportSubmit} className="space-y-4">
              <input required type="text" placeholder="Bus Number" value={newBusSchedule.busNumber} onChange={e => setNewBusSchedule({...newBusSchedule, busNumber: e.target.value})} className="w-full px-4 py-2 border rounded-xl" />
              <input required type="text" placeholder="Route" value={newBusSchedule.route} onChange={e => setNewBusSchedule({...newBusSchedule, route: e.target.value})} className="w-full px-4 py-2 border rounded-xl" />
              <input required type="text" placeholder="Pickup Time" value={newBusSchedule.pickupTime} onChange={e => setNewBusSchedule({...newBusSchedule, pickupTime: e.target.value})} className="w-full px-4 py-2 border rounded-xl" />
              <button type="submit" className="w-full py-3 bg-amber-500 text-white rounded-xl font-bold">Add Route</button>
            </form>
          </div>
        </div>
      )}
      {isTaskModalOpen && renderTaskModal()}
      {isInventoryModalOpen && renderInventoryModal()}
      {renderAiGuidancePanel()}
      {isAiPanelOpen && <div className="fixed inset-0 bg-slate-900/20 z-[55] backdrop-blur-xs" onClick={() => setIsAiPanelOpen(false)} />}

      {/* Sidebar */}
