            key={btn}
            onClick={() => handleCalcAction(btn)}
            className={`h-12 rounded-xl text-sm font-bold transition-all ${
              ['/','*','-','+','='].includes(btn) ? 'bg-indigo-600 text-white hover:bg-indigo-500' :
              btn === 'C' ? 'bg-rose-500 text-white col-span-4' : 'bg-slate-700 text-slate-200 hover:bg-slate-600'
