                          <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase ${i.status === 'In Stock' ? 'bg-emerald-50 text-emerald-600' : 'bg-rose-50 text-rose-600'}`}>
                            {i.status}
                          </span>
                        </td>
                        <td className="px-8 py-6">
                          {i.needed && <span className="text-rose-500 font-black text-xs">⚠️ ACTION REQ</span>}
                        </td>
                      </tr>
                    ))}
                  </tbody>
               </table>
             </div>
           </div>
        )}
        {activeTab === AppTab.POLICIES && (
           <div className="max-w-4xl mx-auto space-y-8 animate-fadeIn">
             <div className="bg-white p-12 rounded-3xl border border-slate-100 shadow-sm relative overflow-hidden">
                <div className="absolute -top-10 -right-10 w-40 h-40 bg-indigo-50 rounded-full blur-3xl" />
                <h2 className="text-4xl font-black text-slate-800 mb-10">Institutional Policy</h2>
                <div className="space-y-12">
                   {MOCK_POLICIES.map(p => (
                     <div key={p.id} className="relative pl-10 border-l-4 border-indigo-600">
                        <span className="text-[10px] font-black uppercase tracking-widest text-indigo-500 block mb-2">{p.target} Policy</span>
                        <h3 className="text-xl font-black text-slate-800 mb-4">{p.title}</h3>
                        <div className="p-8 bg-slate-50 rounded-3xl text-slate-600 leading-relaxed font-medium">
                          {p.content}
                        </div>
                     </div>
                   ))}
                </div>
             </div>
           </div>
        )}
        {activeTab === AppTab.TRANSPORT && (
          <div className="space-y-6">
             <div className="flex justify-between items-center">
                <h2 className="text-2xl font-black text-slate-800">Bus Schedule</h2>
                <button className="px-5 py-2.5 bg-amber-500 text-white rounded-xl text-sm font-black">Add Route</button>
             </div>
             <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                {busSchedules.map(b => (
                  <div key={b.id} className="bg-white p-8 rounded-3xl border border-slate-100 shadow-sm relative group overflow-hidden">
                    <div className="absolute top-0 left-0 w-2 h-full bg-amber-400" />
                    <div className="flex justify-between items-start mb-6">
                      <div className="flex items-center space-x-4">
                        <div className="p-4 bg-amber-50 text-amber-600 rounded-2xl"><Bus size={32} /></div>
                        <div>
                          <h4 className="text-xl font-black text-slate-800">Bus {b.busNumber}</h4>
                          <p className="text-sm font-medium text-slate-400">{b.route}</p>
                        </div>
                      </div>
                      <div className="text-right">
                        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Pickup</p>
                        <p className="text-2xl font-black text-indigo-600">{b.pickupTime}</p>
                      </div>
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                      <div className="p-4 bg-slate-50 rounded-2xl">
                        <p className="text-[10px] font-black text-slate-400 uppercase mb-2">Driver</p>
                        <p className="font-bold text-slate-800">{b.driver.name}</p>
                        <p className="text-xs text-slate-500">{b.driver.phone}</p>
                      </div>
                      <div className="p-4 bg-slate-50 rounded-2xl">
                        <p className="text-[10px] font-black text-slate-400 uppercase mb-2">Home Base</p>
                        <p className="text-xs text-slate-700 font-medium leading-relaxed">{b.driver.homeAddress}</p>
                      </div>
                    </div>
                  </div>
                ))}
             </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

export enum AppTab {
  DASHBOARD = 'dashboard',
  EXPENSES = 'expenses',
  INVENTORY = 'inventory',
  TASKS = 'tasks',
  STAFF = 'staff',
  TRANSPORT = 'transport',
  POLICIES = 'policies'
}

export interface Expense {
  id: string;
  date: string;
  category: string;
  description: string;
  amount: number;
}

export interface Income {
  id: string;
  date: string;
  source: string;
  amount: number;
}

export interface InventoryItem {
  id: string;
  name: string;
  category: string;
  quantity: number;
  status: 'In Stock' | 'Low' | 'Out of Stock';
  needed: boolean;
}

export interface Task {
  id: string;
  title: string;
  dueDate: string;
  priority: 'Low' | 'Medium' | 'High';
  completed: boolean;
}

export interface StaffRecord {
  id: string;
  name: string;
  role: string;
  phone: string;
  email: string;
  guarantor: {
    name: string;
    phone: string;
    address: string;
  };
  agreementSigned: boolean;
  joiningDate: string;
}

export interface BusSchedule {
  id: string;
  busNumber: string;
  route: string;
  pickupTime: string;
  driver: {
    name: string;
    phone: string;
    homeAddress: string;
    agencyDetails: string;
  };
}

export interface Policy {
  id: string;
  target: 'Teachers' | 'Students' | 'Parents';
  title: string;
  content: string;
}

import React, { useState, useMemo, useEffect } from 'react';
import { 
  LayoutDashboard, 
  Wallet, 
  Package, 
  CheckSquare, 
  Users, 
  Bus, 
  FileText, 
  LogOut,
  Bell,
  Search,
  Plus,
  ArrowUpRight,
  TrendingUp,
  Activity,
  X,
  Save,
  Clock,
  MapPin,
  ShieldCheck,
  Sparkles,
  Loader2,
  ChevronRight,
  AlertTriangle,
  BrainCircuit,
  Calculator,
  ArrowDownRight,
  Coins,
  TrendingDown,
  Target
} from 'lucide-react';
import { GoogleGenAI } from "@google/genai";
import { AppTab, Expense, Income, InventoryItem, Task, StaffRecord, BusSchedule, Policy } from './types';
import { MOCK_EXPENSES, MOCK_INVENTORY, MOCK_TASKS, MOCK_STAFF, MOCK_BUS, MOCK_POLICIES } from './constants';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';

const storage = {
  get: <T,>(key: string, defaultValue: T): T => {
    const saved = localStorage.getItem(`pb_portal_${key}`);
    return saved ? JSON.parse(saved) : defaultValue;
  },
  set: <T,>(key: string, value: T): void => {
    localStorage.setItem(`pb_portal_${key}`, JSON.stringify(value));
  }
};

const SidebarItem: React.FC<{ 
  icon: React.ElementType; 
  label: string; 
  active: boolean; 
  onClick: () => void 
}> = ({ icon: Icon, label, active, onClick }) => (
  <button
    onClick={onClick}
    className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl transition-all duration-200 ${
      active 
        ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-100' 
        : 'text-slate-500 hover:bg-slate-100'
    }`}
  >
    <Icon size={20} />
    <span className="font-semibold text-sm">{label}</span>
  </button>
);

const StatCard: React.FC<{ icon: React.ElementType; label: string; value: string; color: string }> = ({ icon: Icon, label, value, color }) => (
  <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm flex items-center space-x-4">
    <div className={`p-3 rounded-xl ${color} bg-opacity-10 text-${color.split('-')[1]}-600`}>
      <Icon size={24} />
    </div>
    <div>
      <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest">{label}</p>
      <h3 className="text-xl font-bold text-slate-800">{value}</h3>
    </div>
  </div>
);

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.DASHBOARD);

  const [expenses, setExpenses] = useState<Expense[]>(() => storage.get('expenses', MOCK_EXPENSES));
  const [income, setIncome] = useState<Income[]>(() => storage.get('income', []));
  const [inventory, setInventory] = useState<InventoryItem[]>(() => storage.get('inventory', MOCK_INVENTORY));
  const [tasks, setTasks] = useState<Task[]>(() => storage.get('tasks', MOCK_TASKS));
  const [staff, setStaff] = useState<StaffRecord[]>(() => storage.get('staff', MOCK_STAFF));
  const [busSchedules, setBusSchedules] = useState<BusSchedule[]>(() => storage.get('busSchedules', MOCK_BUS));

  useEffect(() => storage.set('expenses', expenses), [expenses]);
  useEffect(() => storage.set('income', income), [income]);
  useEffect(() => storage.set('inventory', inventory), [inventory]);
  useEffect(() => storage.set('tasks', tasks), [tasks]);
  useEffect(() => storage.set('staff', staff), [staff]);
  useEffect(() => storage.set('busSchedules', busSchedules), [busSchedules]);

  const [isStaffModalOpen, setIsStaffModalOpen] = useState(false);
  const [isTransportModalOpen, setIsTransportModalOpen] = useState(false);
  const [isTaskModalOpen, setIsTaskModalOpen] = useState(false);
  const [isInventoryModalOpen, setIsInventoryModalOpen] = useState(false);
  const [isExpenseModalOpen, setIsExpenseModalOpen] = useState(false);
  const [isIncomeModalOpen, setIsIncomeModalOpen] = useState(false);
  const [isAiPanelOpen, setIsAiPanelOpen] = useState(false);
  const [isCalculatorOpen, setIsCalculatorOpen] = useState(false);
  const [aiGuidance, setAiGuidance] = useState<{title: string, content: string} | null>(null);
  const [isAiLoading, setIsAiLoading] = useState(false);

  const [calcDisplay, setCalcDisplay] = useState('0');
  const [calcMemory, setCalcMemory] = useState<number | null>(null);
  const [calcOp, setCalcOp] = useState<string | null>(null);

  const [newExpense, setNewExpense] = useState<Omit<Expense, 'id'>>({
    date: new Date().toISOString().split('T')[0],
    category: 'Operational',
    description: '',
    amount: 0
  });

  const [newIncome, setNewIncome] = useState<Omit<Income, 'id'>>({
    date: new Date().toISOString().split('T')[0],
    source: 'School Fees',
    amount: 0
  });

  const [newStaff, setNewStaff] = useState({ name: '', role: '', phone: '', email: '' });
  const [newTask, setNewTask] = useState<Omit<Task, 'id' | 'completed'>>({
    title: '',
    dueDate: new Date().toISOString().split('T')[0],
    priority: 'Medium'
  });

  const [newInventoryItem, setNewInventoryItem] = useState<Omit<InventoryItem, 'id'>>({
    name: '', category: 'Stationery', quantity: 0, status: 'In Stock', needed: false
  });

  const totalExpenses = useMemo(() => expenses.reduce((acc, curr) => acc + curr.amount, 0), [expenses]);
  const totalIncome = useMemo(() => income.reduce((acc, curr) => acc + curr.amount, 0), [income]);
  const netProfit = totalIncome - totalExpenses;
  const isProfitable = netProfit > 0;
  const profitMargin = totalIncome > 0 ? (netProfit / totalIncome) * 100 : 0;

  const pendingTasksCount = useMemo(() => tasks.filter(t => !t.completed).length, [tasks]);
  const itemsNeededCount = useMemo(() => inventory.filter(i => i.needed).length, [inventory]);

  const handleCalc = (btn: string) => {
    if (btn === 'C') {
      setCalcDisplay('0');
      setCalcMemory(null);
      setCalcOp(null);
    } else if (['+', '-', '*', '/'].includes(btn)) {
      setCalcMemory(parseFloat(calcDisplay));
      setCalcOp(btn);
      setCalcDisplay('0');
    } else if (btn === '=') {
      if (calcMemory !== null && calcOp) {
        const current = parseFloat(calcDisplay);
        let res = 0;
        if (calcOp === '+') res = calcMemory + current;
        if (calcOp === '-') res = calcMemory - current;
        if (calcOp === '*') res = calcMemory * current;
        if (calcOp === '/') res = calcMemory / current;
        setCalcDisplay(res.toString());
        setCalcMemory(null);
        setCalcOp(null);
      }
    } else {
      setCalcDisplay(calcDisplay === '0' ? btn : calcDisplay + btn);
    }
  };

  const getAiGuidance = async (context: 'task' | 'inventory', data: any) => {
    setIsAiLoading(true);
    setIsAiPanelOpen(true);
    const title = context === 'task' ? data.title : "Smart Inventory Sort";
    setAiGuidance({ title, content: '' });
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      let prompt = context === 'task' 
        ? `Madam Gloria needs a plan for: ${data.title}. Provide a step-by-step action plan.`
        : `School inventory: ${inventory.map(i => `${i.name} (${i.quantity})`).join(', ')}. Which items need urgent fetching and why? Sort them by importance.`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });
      setAiGuidance({ title, content: response.text || "No guidance available." });
    } catch (e) {
      setAiGuidance({ title, content: "AI assistant offline." });
    } finally {
      setIsAiLoading(false);
    }
  };

  const handleExpenseSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setExpenses([{ ...newExpense, id: Date.now().toString() }, ...expenses]);
    setIsExpenseModalOpen(false);
    setNewExpense({ date: new Date().toISOString().split('T')[0], category: 'Operational', description: '', amount: 0 });
  };

  const handleIncomeSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setIncome([{ ...newIncome, id: Date.now().toString() }, ...income]);
    setIsIncomeModalOpen(false);
    setNewIncome({ date: new Date().toISOString().split('T')[0], source: 'School Fees', amount: 0 });
  };

  const handleStaffSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setStaff([{ ...newStaff, id: Date.now().toString(), joiningDate: new Date().toISOString().split('T')[0], agreementSigned: false, guarantor: { name: '', phone: '', address: '' } }, ...staff]);
    setIsStaffModalOpen(false);
    setNewStaff({ name: '', role: '', phone: '', email: '' });
  };

  const handleTaskSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setTasks([{ ...newTask, id: Date.now().toString(), completed: false }, ...tasks]);
    setIsTaskModalOpen(false);
    setNewTask({ title: '', dueDate: new Date().toISOString().split('T')[0], priority: 'Medium' });
  };

  const handleInventorySubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const status = newInventoryItem.quantity < 10 ? 'Low' : 'In Stock';
    setInventory([{ ...newInventoryItem, id: Date.now().toString(), status, needed: status === 'Low' }, ...inventory]);
    setIsInventoryModalOpen(false);
    setNewInventoryItem({ name: '', category: 'Stationery', quantity: 0, status: 'In Stock', needed: false });
  };

  const renderExpenses = () => (
    <div className="space-y-6 animate-fadeIn">
      {/* Financial Indicators */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="bg-white p-8 rounded-3xl border border-slate-100 shadow-sm flex flex-col justify-between relative overflow-hidden">
          <div className="absolute -top-10 -right-10 w-40 h-40 bg-indigo-50 rounded-full opacity-50 blur-3xl"></div>
          <div>
            <div className="flex justify-between items-start mb-4">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Net School Progress</p>
              <Target size={18} className="text-indigo-400" />
            </div>
            <h3 className={`text-3xl font-black ${isProfitable ? 'text-emerald-600' : 'text-rose-600'}`}>
              ₦{netProfit.toLocaleString()}
            </h3>
            <p className="text-xs text-slate-500 mt-2 font-medium">
              Madam Gloria, the school is currently <span className={`font-black uppercase ${isProfitable ? 'text-emerald-500' : 'text-rose-500'}`}>
                {isProfitable ? 'Growing' : 'Losing Funds'}
              </span>
            </p>
          </div>
          <div className="mt-8">
            <div className="flex justify-between text-[10px] font-black text-slate-400 mb-2">
              <span>PROFIT MARGIN</span>
              <span>{profitMargin.toFixed(1)}%</span>
            </div>
            <div className="h-2.5 bg-slate-100 rounded-full overflow-hidden">
              <div 
                className={`h-full transition-all duration-700 ${isProfitable ? 'bg-emerald-500 shadow-[0_0_10px_rgba(16,185,129,0.3)]' : 'bg-rose-500 shadow-[0_0_10px_rgba(244,63,94,0.3)]'}`} 
                style={{ width: `${Math.min(Math.max(profitMargin, 5), 100)}%` }} 
              />
            </div>
          </div>
        </div>

        <StatCard icon={Coins} label="Total Revenue (₦)" value={`₦${totalIncome.toLocaleString()}`} color="bg-emerald-500" />
        <StatCard icon={TrendingDown} label="Total Expenditure (₦)" value={`₦${totalExpenses.toLocaleString()}`} color="bg-rose-500" />
      </div>

      <div className="flex justify-between items-center bg-white p-4 rounded-3xl border border-slate-100 shadow-sm">
        <div className="flex items-center space-x-4">
          <button 
            onClick={() => setIsCalculatorOpen(!isCalculatorOpen)}
            className={`flex items-center space-x-2 px-4 py-2.5 rounded-2xl transition-all font-bold text-xs ${isCalculatorOpen ? 'bg-slate-900 text-white' : 'bg-slate-50 text-slate-500 hover:bg-slate-100'}`}
          >
            <Calculator size={16} />
            <span>Built-in Calculator</span>
          </button>
          {isCalculatorOpen && (
            <div className="fixed inset-0 z-[110] flex items-center justify-center pointer-events-none">
              <div className="bg-slate-900 p-6 rounded-[2.5rem] shadow-2xl w-72 pointer-events-auto border-4 border-slate-800 animate-scaleIn">
                <div className="flex justify-between items-center mb-6">
                  <span className="text-white/50 text-[10px] font-black uppercase tracking-widest">School Calc</span>
                  <button onClick={() => setIsCalculatorOpen(false)} className="text-white/30 hover:text-white"><X size={16} /></button>
                </div>
                <div className="bg-slate-800 p-5 rounded-3xl mb-6 text-right">
                  <p className="text-indigo-400 text-xs font-bold h-4">{calcMemory} {calcOp}</p>
                  <p className="text-white text-3xl font-black truncate">{calcDisplay}</p>
                </div>
                <div className="grid grid-cols-4 gap-2.5">
                  {['7','8','9','/','4','5','6','*','1','2','3','-','0','.','=','+','C'].map(btn => (
                    <button 
                      key={btn} 
                      onClick={() => handleCalc(btn)}
                      className={`h-12 rounded-2xl text-sm font-black transition-all ${
                        ['/','*','-','+','='].includes(btn) ? 'bg-indigo-600 text-white hover:bg-indigo-500' :
                        btn === 'C' ? 'bg-rose-500 text-white col-span-4' : 'bg-slate-700 text-slate-200 hover:bg-slate-600'
                      }`}
                    >
                      {btn}
                    </button>
                  ))}
                </div>
              </div>
            </div>
          )}
        </div>
        <div className="flex space-x-3">
          <button 
            onClick={() => setIsIncomeModalOpen(true)}
            className="flex items-center space-x-2 px-5 py-2.5 bg-emerald-600 text-white rounded-2xl text-xs font-black shadow-lg shadow-emerald-100 hover:bg-emerald-700 transition-all"
          >
            <Plus size={16} />
            <span>Record Income</span>
          </button>
          <button 
            onClick={() => setIsExpenseModalOpen(true)}
            className="flex items-center space-x-2 px-5 py-2.5 bg-rose-600 text-white rounded-2xl text-xs font-black shadow-lg shadow-rose-100 hover:bg-rose-700 transition-all"
          >
            <Plus size={16} />
            <span>New Expense</span>
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-2 gap-6">
        <div className="bg-white rounded-[2rem] border border-slate-100 shadow-sm overflow-hidden">
          <div className="p-6 border-b border-slate-50 flex items-center justify-between bg-slate-50/50">
            <h3 className="font-black text-slate-800 flex items-center text-sm">
              <Coins size={18} className="mr-2 text-emerald-500" /> Income Log
            </h3>
          </div>
          <div className="overflow-x-auto max-h-[400px]">
            <table className="w-full text-left">
              <thead>
                <tr className="text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">
                  <th className="px-6 py-4">Date</th>
                  <th className="px-6 py-4">Source</th>
                  <th className="px-6 py-4 text-right">Amount</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {income.map(i => (
                  <tr key={i.id} className="hover:bg-emerald-50/20 group transition-all">
                    <td className="px-6 py-4 text-xs font-bold text-slate-400">{i.date}</td>
                    <td className="px-6 py-4 text-sm font-black text-slate-700">{i.source}</td>
                    <td className="px-6 py-4 text-right font-black text-emerald-600">₦{i.amount.toLocaleString()}</td>
                  </tr>
                ))}
                {income.length === 0 && (
                  <tr><td colSpan={3} className="p-12 text-center text-slate-400 italic text-sm">No income records found.</td></tr>
                )}
              </tbody>
            </table>
          </div>
        </div>

        <div className="bg-white rounded-[2rem] border border-slate-100 shadow-sm overflow-hidden">
          <div className="p-6 border-b border-slate-50 flex items-center justify-between bg-slate-50/50">
            <h3 className="font-black text-slate-800 flex items-center text-sm">
              <TrendingDown size={18} className="mr-2 text-rose-500" /> Expenditure Log
            </h3>
          </div>
          <div className="overflow-x-auto max-h-[400px]">
            <table className="w-full text-left">
              <thead>
                <tr className="text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">
                  <th className="px-6 py-4">Date</th>
                  <th className="px-6 py-4">Category</th>
                  <th className="px-6 py-4 text-right">Amount</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {expenses.map(e => (
                  <tr key={e.id} className="hover:bg-rose-50/20 group transition-all">
                    <td className="px-6 py-4 text-xs font-bold text-slate-400">{e.date}</td>
                    <td className="px-6 py-4 text-sm font-black text-slate-700">{e.category}</td>
                    <td className="px-6 py-4 text-right font-black text-rose-600">₦{e.amount.toLocaleString()}</td>
                  </tr>
                ))}
                {expenses.length === 0 && (
                  <tr><td colSpan={3} className="p-12 text-center text-slate-400 italic text-sm">No expenditure records.</td></tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );

  const renderDashboard = () => (
    <div className="space-y-6 animate-fadeIn">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <StatCard icon={TrendingUp} label="Current Health" value={`₦${netProfit.toLocaleString()}`} color={isProfitable ? "bg-emerald-500" : "bg-rose-500"} />
        <StatCard icon={CheckSquare} label="Pending Tasks" value={pendingTasksCount.toString()} color="bg-amber-500" />
        <StatCard icon={Package} label="Low Stocks" value={itemsNeededCount.toString()} color="bg-indigo-500" />
        <StatCard icon={Activity} label="Total Staff" value={staff.length.toString()} color="bg-blue-500" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 bg-white p-8 rounded-3xl border border-slate-100 shadow-sm">
