        </div>
      </div>
      {isAiPanelOpen && <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-[140] transition-opacity" onClick={() => setIsAiPanelOpen(false)} />}
    </div>
  );
};

export default App;
